'use client';

import { Briefcase } from 'lucide-react';
import { useCallback, useEffect, useState, type FormEvent } from 'react';

import type {
  Company,
  CompanyListResponse,
  JobListing,
  JobListingListResponse,
  JobScanCreateResponse,
  JobScanListResponse,
  JobScanRecord,
  JobScanProvider,
} from '@/shared/contracts/job-board';
import { AdminJobBoardPageLayout } from '@/shared/ui/admin-job-board-page-layout';
import { Button } from '@/shared/ui/button';
import { SelectSimple } from '@/shared/ui/forms-and-actions.public';
import { Input } from '@/shared/ui/input';

import { JobScanDetailDialog } from './JobScanDetailDialog';

const SCANS_ENDPOINT = '/api/v2/jobs/scans';
const COMPANIES_ENDPOINT = '/api/v2/jobs/companies';
const LISTINGS_ENDPOINT = '/api/v2/jobs/listings';

type Tab = 'scans' | 'companies' | 'listings' | 'promotions';
type JobScanProviderSelection = 'auto' | JobScanProvider;

const JOB_SCAN_PROVIDER_OPTIONS = [
  { value: 'auto', label: 'Auto-detect' },
  { value: 'pracuj_pl', label: 'Pracuj.pl' },
  { value: 'justjoin_it', label: 'Just Join IT' },
  { value: 'nofluffjobs', label: 'No Fluff Jobs' },
] as const;

type PromotionLogEntry = {
  scanId: string;
  scanSourceUrl: string;
  companyId: string | null;
  companyName: string | null;
  kind: 'auto' | 'manual';
  status: 'completed' | 'skipped' | 'failed' | 'pending' | 'running';
  message: string | null;
  startedAt: string | null;
  completedAt: string | null;
  durationMs: number | null;
};

const PROMOTION_STEP_KEYS: Record<string, PromotionLogEntry['kind']> = {
  auto_promote: 'auto',
  manual_promote: 'manual',
};

const collectPromotionLog = (scans: JobScanRecord[], companies: Company[]): PromotionLogEntry[] => {
  const companyById = new Map(companies.map((c) => [c.id, c]));
  const entries: PromotionLogEntry[] = [];
  for (const scan of scans) {
    for (const step of scan.steps) {
      const kind = PROMOTION_STEP_KEYS[step.key];
      if (!kind) continue;
      const company = scan.companyId ? companyById.get(scan.companyId) ?? null : null;
      entries.push({
        scanId: scan.id,
        scanSourceUrl: scan.sourceUrl,
        companyId: scan.companyId,
        companyName:
          company?.name ??
          ((scan.evaluation?.company as Record<string, unknown> | null)?.['name'] as
            | string
            | undefined) ??
          null,
        kind,
        status: step.status,
        message: step.message,
        startedAt: step.startedAt,
        completedAt: step.completedAt,
        durationMs: step.durationMs,
      });
    }
  }
  return entries.sort((a, b) => {
    const aTs = a.completedAt ? Date.parse(a.completedAt) : 0;
    const bTs = b.completedAt ? Date.parse(b.completedAt) : 0;
    return bTs - aTs;
  });
};

const promotionStatusBadge = (status: PromotionLogEntry['status']): string => {
  switch (status) {
    case 'completed':
      return 'bg-emerald-100 text-emerald-800';
    case 'skipped':
      return 'bg-slate-100 text-slate-700';
    case 'failed':
      return 'bg-rose-100 text-rose-800';
    default:
      return 'bg-amber-100 text-amber-800';
  }
};

const statusBadge = (status: JobScanRecord['status']): string => {
  switch (status) {
    case 'completed':
      return 'bg-emerald-100 text-emerald-800';
    case 'running':
    case 'queued':
      return 'bg-blue-100 text-blue-800';
    case 'failed':
      return 'bg-rose-100 text-rose-800';
    case 'no_match':
      return 'bg-amber-100 text-amber-800';
    default:
      return 'bg-slate-100 text-slate-800';
  }
};

const formatSalary = (salary: JobListing['salary']): string => {
  if (!salary) return '—';
  if (salary.raw) return salary.raw;
  const min = salary.min;
  const max = salary.max;
  const currency = salary.currency ?? '';
  const period = salary.period ? ` / ${salary.period}` : '';
  if (min != null && max != null) return `${min}–${max} ${currency}${period}`.trim();
  if (min != null) return `from ${min} ${currency}${period}`.trim();
  if (max != null) return `up to ${max} ${currency}${period}`.trim();
  return '—';
};

export function AdminJobBoardPage(): React.JSX.Element {
  const [tab, setTab] = useState<Tab>('scans');
  const [sourceUrl, setSourceUrl] = useState('');
  const [provider, setProvider] = useState<JobScanProviderSelection>('auto');
  const [useVisionEmailFinder, setUseVisionEmailFinder] = useState(false);
  const [scans, setScans] = useState<JobScanRecord[]>([]);
  const [companies, setCompanies] = useState<Company[]>([]);
  const [listings, setListings] = useState<JobListing[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedScan, setSelectedScan] = useState<JobScanRecord | null>(null);

  const loadAll = useCallback(async (): Promise<void> => {
    setIsLoading(true);
    setError(null);
    try {
      const [scansRes, companiesRes, listingsRes] = await Promise.all([
        fetch(SCANS_ENDPOINT, { cache: 'no-store' }),
        fetch(COMPANIES_ENDPOINT, { cache: 'no-store' }),
        fetch(LISTINGS_ENDPOINT, { cache: 'no-store' }),
      ]);
      if (!scansRes.ok) throw new Error(`Scans HTTP ${scansRes.status}`);
      if (!companiesRes.ok) throw new Error(`Companies HTTP ${companiesRes.status}`);
      if (!listingsRes.ok) throw new Error(`Listings HTTP ${listingsRes.status}`);
      const scansBody = (await scansRes.json()) as JobScanListResponse;
      const companiesBody = (await companiesRes.json()) as CompanyListResponse;
      const listingsBody = (await listingsRes.json()) as JobListingListResponse;
      setScans(scansBody.scans);
      setCompanies(companiesBody.companies);
      setListings(listingsBody.listings);
    } catch (err) {
      setError(err instanceof Error ? err.message : String(err));
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    void loadAll();
  }, [loadAll]);

  const hasActiveScan = scans.some((s) => s.status === 'queued' || s.status === 'running');

  useEffect(() => {
    if (!hasActiveScan) return;
    const handle = window.setInterval(() => {
      void loadAll();
    }, 3000);
    return () => window.clearInterval(handle);
  }, [hasActiveScan, loadAll]);

  // Keep the open scan-detail dialog's data in sync with refreshed scans (e.g. after a manual
  // promote appends a `manual_promote` step). Compare by id so a stale closure-captured object
  // doesn't suppress the update.
  useEffect(() => {
    if (!selectedScan) return;
    const refreshed = scans.find((s) => s.id === selectedScan.id);
    if (refreshed && refreshed !== selectedScan) {
      setSelectedScan(refreshed);
    }
  }, [scans, selectedScan]);

  const handleSubmit = useCallback(
    async (event: FormEvent<HTMLFormElement>): Promise<void> => {
      event.preventDefault();
      const url = sourceUrl.trim();
      if (!url) return;
      setIsSubmitting(true);
      setError(null);
      try {
        const response = await fetch(SCANS_ENDPOINT, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            sourceUrl: url,
            useVision: useVisionEmailFinder,
            ...(provider !== 'auto' ? { provider } : {}),
          }),
        });
        if (!response.ok) {
          const text = await response.text();
          throw new Error(text || `Submit failed (HTTP ${response.status})`);
        }
        const body = (await response.json()) as JobScanCreateResponse;
        setScans((prev) => [body.scan, ...prev.filter((s) => s.id !== body.scan.id)]);
        setSourceUrl('');
        void loadAll();
      } catch (err) {
        setError(err instanceof Error ? err.message : String(err));
      } finally {
        setIsSubmitting(false);
      }
    },
    [sourceUrl, provider, useVisionEmailFinder, loadAll]
  );

  const handleCompanyUpdated = useCallback((updatedCompany: Company): void => {
    setCompanies((prev) =>
      prev.map((company) =>
        company.id === updatedCompany.id ? updatedCompany : company
      )
    );
  }, []);

  const companyNameById = new Map(companies.map((c) => [c.id, c.name]));
  const promotionLog = collectPromotionLog(scans, companies);

  return (
    <AdminJobBoardPageLayout
      title='Job Board Scraper'
      current='Job Board Scraper'
      description='Scrape job offers from pracuj.pl, Just Join IT, or No Fluff Jobs, extract company + listing data with AI, and persist them.'
      icon={<Briefcase className='size-4' />}
    >
      <form
        onSubmit={(event) => void handleSubmit(event)}
        className='mb-6 flex flex-col gap-3 sm:flex-row sm:items-center'
      >
        <Input
          type='url'
          required
          placeholder='https://www.pracuj.pl/... or https://justjoin.it/...'
          value={sourceUrl}
          onChange={(event) => setSourceUrl(event.target.value)}
          className='flex-1'
        />
        <div className='w-full sm:w-52'>
          <SelectSimple
            ariaLabel='Job board provider'
            value={provider}
            options={JOB_SCAN_PROVIDER_OPTIONS}
            onValueChange={(value) => setProvider(value as JobScanProviderSelection)}
          />
        </div>
        <label className='flex items-center gap-2 rounded border border-slate-200 px-3 py-2 text-sm text-slate-700'>
          <input
            type='checkbox'
            aria-label='AI vision email route'
            checked={useVisionEmailFinder}
            onChange={(event) => setUseVisionEmailFinder(event.target.checked)}
          />
          <span>
            AI vision email route
            <span className='block text-xs text-slate-500'>Off: preset contact-page routes</span>
          </span>
        </label>
        <div className='flex gap-2'>
          <Button type='submit' disabled={isSubmitting}>
            {isSubmitting ? 'Scanning...' : 'Scrape & save'}
          </Button>
          <Button
            type='button'
            variant='outline'
            disabled={isLoading}
            onClick={() => void loadAll()}
          >
            {isLoading ? 'Loading...' : 'Refresh'}
          </Button>
        </div>
      </form>

      {error ? (
        <div className='mb-4 rounded border border-rose-300 bg-rose-50 p-3 text-sm text-rose-800'>
          {error}
        </div>
      ) : null}

      <div className='mb-4 flex gap-2 border-b border-slate-200'>
        {(['scans', 'companies', 'listings', 'promotions'] as Tab[]).map((value) => (
          <button
            key={value}
            type='button'
            onClick={() => setTab(value)}
            className={`-mb-px border-b-2 px-3 py-2 text-sm font-medium capitalize ${
              tab === value
                ? 'border-blue-500 text-blue-700'
                : 'border-transparent text-slate-500 hover:text-slate-700'
            }`}
          >
            {value} (
            {value === 'scans'
              ? scans.length
              : value === 'companies'
                ? companies.length
                : value === 'listings'
                  ? listings.length
                  : promotionLog.length}
            )
          </button>
        ))}
      </div>

      {tab === 'scans' ? (
        <ScansTable scans={scans} isLoading={isLoading} onSelect={setSelectedScan} />
      ) : tab === 'companies' ? (
        <CompaniesTable companies={companies} isLoading={isLoading} />
      ) : tab === 'listings' ? (
        <ListingsTable
          listings={listings}
          isLoading={isLoading}
          companyNameById={companyNameById}
        />
      ) : (
        <PromotionsTable
          entries={promotionLog}
          isLoading={isLoading}
          onSelectScan={(scanId) => {
            const scan = scans.find((s) => s.id === scanId);
            if (scan) setSelectedScan(scan);
          }}
        />
      )}

      <JobScanDetailDialog
        scan={selectedScan}
        company={
          selectedScan?.companyId
            ? companies.find((c) => c.id === selectedScan.companyId) ?? null
            : null
        }
        onClose={() => setSelectedScan(null)}
        onCompanyUpdated={handleCompanyUpdated}
        onPromoted={() => {
          void loadAll();
        }}
      />
    </AdminJobBoardPageLayout>
  );
}

function ScansTable({
  scans,
  isLoading,
  onSelect,
}: {
  scans: JobScanRecord[];
  isLoading: boolean;
  onSelect: (scan: JobScanRecord) => void;
}): React.JSX.Element {
  return (
    <div className='overflow-x-auto rounded-lg border border-slate-200'>
      <table className='min-w-full divide-y divide-slate-200 text-sm'>
        <thead className='bg-slate-50 text-left'>
          <tr>
            <th className='px-4 py-2 font-medium'>Status</th>
            <th className='px-4 py-2 font-medium'>Job title</th>
            <th className='px-4 py-2 font-medium'>Company</th>
            <th className='px-4 py-2 font-medium'>Source URL</th>
            <th className='px-4 py-2 font-medium'>Confidence</th>
            <th className='px-4 py-2 font-medium'>Created</th>
          </tr>
        </thead>
        <tbody className='divide-y divide-slate-100 bg-white'>
          {scans.length === 0 ? (
            <tr>
              <td colSpan={6} className='px-4 py-8 text-center text-slate-500'>
                {isLoading ? 'Loading...' : 'No scans yet. Submit a URL above to start.'}
              </td>
            </tr>
          ) : (
            scans.map((scan) => {
              const listing = (scan.evaluation?.listing as Record<string, unknown> | null) ?? null;
              const company = (scan.evaluation?.company as Record<string, unknown> | null) ?? null;
              const title = (listing?.['title'] as string | undefined) ?? '—';
              const companyName = (company?.['name'] as string | undefined) ?? '—';
              const confidence = scan.evaluation?.confidence;
              return (
                <tr
                  key={scan.id}
                  className='cursor-pointer hover:bg-slate-50'
                  onClick={() => onSelect(scan)}
                >
                  <td className='px-4 py-2'>
                    <span
                      className={`inline-flex rounded px-2 py-0.5 text-xs font-medium ${statusBadge(
                        scan.status
                      )}`}
                    >
                      {scan.status}
                    </span>
                  </td>
                  <td className='max-w-xs truncate px-4 py-2'>{title}</td>
                  <td className='max-w-xs truncate px-4 py-2'>{companyName}</td>
                  <td className='max-w-md truncate px-4 py-2'>
                    <a
                      href={scan.sourceUrl}
                      target='_blank'
                      rel='noreferrer'
                      className='text-blue-600 hover:underline'
                      onClick={(event) => event.stopPropagation()}
                    >
                      {scan.sourceUrl}
                    </a>
                  </td>
                  <td className='px-4 py-2'>
                    {typeof confidence === 'number' ? confidence.toFixed(2) : '—'}
                  </td>
                  <td className='whitespace-nowrap px-4 py-2 text-slate-500'>
                    {scan.createdAt ? new Date(scan.createdAt).toLocaleString() : '—'}
                  </td>
                </tr>
              );
            })
          )}
        </tbody>
      </table>
    </div>
  );
}

function CompaniesTable({
  companies,
  isLoading,
}: {
  companies: Company[];
  isLoading: boolean;
}): React.JSX.Element {
  return (
    <div className='overflow-x-auto rounded-lg border border-slate-200'>
      <table className='min-w-full divide-y divide-slate-200 text-sm'>
        <thead className='bg-slate-50 text-left'>
          <tr>
            <th className='px-4 py-2 font-medium'>Name</th>
            <th className='px-4 py-2 font-medium'>NIP</th>
            <th className='px-4 py-2 font-medium'>Domain</th>
            <th className='px-4 py-2 font-medium'>Email</th>
            <th className='px-4 py-2 font-medium'>City</th>
            <th className='px-4 py-2 font-medium'>Industry</th>
          </tr>
        </thead>
        <tbody className='divide-y divide-slate-100 bg-white'>
          {companies.length === 0 ? (
            <tr>
              <td colSpan={6} className='px-4 py-8 text-center text-slate-500'>
                {isLoading ? 'Loading...' : 'No companies yet.'}
              </td>
            </tr>
          ) : (
            companies.map((company) => {
              const primary =
                company.emails.find((e) => e.isPrimary) ?? company.emails[0] ?? null;
              return (
                <tr key={company.id}>
                  <td className='px-4 py-2 font-medium'>{company.name}</td>
                  <td className='px-4 py-2'>{company.nip ?? '—'}</td>
                  <td className='px-4 py-2'>{company.domain ?? '—'}</td>
                  <td className='max-w-xs truncate px-4 py-2'>
                    {primary ? (
                      <a
                        href={`mailto:${primary.address}`}
                        className='text-blue-600 hover:underline'
                      >
                        {primary.address}
                      </a>
                    ) : (
                      <span className='text-slate-400'>—</span>
                    )}
                    {company.emails.length > 1 ? (
                      <span className='ml-1 text-xs text-slate-500'>
                        +{company.emails.length - 1}
                      </span>
                    ) : null}
                  </td>
                  <td className='px-4 py-2'>{company.city ?? '—'}</td>
                  <td className='px-4 py-2'>{company.industry ?? '—'}</td>
                </tr>
              );
            })
          )}
        </tbody>
      </table>
    </div>
  );
}

function ListingsTable({
  listings,
  isLoading,
  companyNameById,
}: {
  listings: JobListing[];
  isLoading: boolean;
  companyNameById: Map<string, string>;
}): React.JSX.Element {
  return (
    <div className='overflow-x-auto rounded-lg border border-slate-200'>
      <table className='min-w-full divide-y divide-slate-200 text-sm'>
        <thead className='bg-slate-50 text-left'>
          <tr>
            <th className='px-4 py-2 font-medium'>Title</th>
            <th className='px-4 py-2 font-medium'>Company</th>
            <th className='px-4 py-2 font-medium'>Mode</th>
            <th className='px-4 py-2 font-medium'>Level</th>
            <th className='px-4 py-2 font-medium'>City</th>
            <th className='px-4 py-2 font-medium'>Salary</th>
            <th className='px-4 py-2 font-medium'>Source</th>
          </tr>
        </thead>
        <tbody className='divide-y divide-slate-100 bg-white'>
          {listings.length === 0 ? (
            <tr>
              <td colSpan={7} className='px-4 py-8 text-center text-slate-500'>
                {isLoading ? 'Loading...' : 'No job listings yet.'}
              </td>
            </tr>
          ) : (
            listings.map((listing) => (
              <tr key={listing.id}>
                <td className='max-w-xs truncate px-4 py-2 font-medium'>{listing.title}</td>
                <td className='max-w-xs truncate px-4 py-2'>
                  {companyNameById.get(listing.companyId) ?? listing.companyId}
                </td>
                <td className='px-4 py-2'>{listing.workMode}</td>
                <td className='px-4 py-2'>{listing.experienceLevel}</td>
                <td className='px-4 py-2'>{listing.city ?? '—'}</td>
                <td className='px-4 py-2'>{formatSalary(listing.salary)}</td>
                <td className='max-w-xs truncate px-4 py-2'>
                  <a
                    href={listing.sourceUrl}
                    target='_blank'
                    rel='noreferrer'
                    className='text-blue-600 hover:underline'
                  >
                    open
                  </a>
                </td>
              </tr>
            ))
          )}
        </tbody>
      </table>
    </div>
  );
}

function PromotionsTable({
  entries,
  isLoading,
  onSelectScan,
}: {
  entries: PromotionLogEntry[];
  isLoading: boolean;
  onSelectScan: (scanId: string) => void;
}): React.JSX.Element {
  const completed = entries.filter((entry) => entry.status === 'completed').length;
  const skipped = entries.filter((entry) => entry.status === 'skipped').length;
  const failed = entries.filter((entry) => entry.status === 'failed').length;

  return (
    <div className='space-y-3'>
      <div className='flex flex-wrap gap-3 text-sm'>
        <span className='inline-flex items-center gap-1 rounded bg-emerald-50 px-2 py-1 font-medium text-emerald-800'>
          {completed} completed
        </span>
        <span className='inline-flex items-center gap-1 rounded bg-slate-50 px-2 py-1 font-medium text-slate-700'>
          {skipped} skipped
        </span>
        <span className='inline-flex items-center gap-1 rounded bg-rose-50 px-2 py-1 font-medium text-rose-800'>
          {failed} failed
        </span>
      </div>
      <div className='overflow-x-auto rounded-lg border border-slate-200'>
        <table className='min-w-full divide-y divide-slate-200 text-sm'>
          <thead className='bg-slate-50 text-left'>
            <tr>
              <th className='px-4 py-2 font-medium'>Status</th>
              <th className='px-4 py-2 font-medium'>Kind</th>
              <th className='px-4 py-2 font-medium'>Company</th>
              <th className='px-4 py-2 font-medium'>Outcome</th>
              <th className='px-4 py-2 font-medium'>Source URL</th>
              <th className='px-4 py-2 font-medium'>When</th>
              <th className='px-4 py-2 font-medium'>Duration</th>
            </tr>
          </thead>
          <tbody className='divide-y divide-slate-100 bg-white'>
            {entries.length === 0 ? (
              <tr>
                <td colSpan={7} className='px-4 py-8 text-center text-slate-500'>
                  {isLoading
                    ? 'Loading...'
                    : 'No promote attempts yet. Set JOB_BOARD_AUTO_PROMOTE_ON_NIP_MATCH=true for auto-promote, or use Promote to Organiser… in the scan detail.'}
                </td>
              </tr>
            ) : (
              entries.map((entry, idx) => (
                <tr
                  key={`${entry.scanId}-${idx}`}
                  className='cursor-pointer hover:bg-slate-50'
                  onClick={() => onSelectScan(entry.scanId)}
                >
                  <td className='px-4 py-2'>
                    <span
                      className={`inline-flex rounded px-2 py-0.5 text-xs font-medium ${promotionStatusBadge(
                        entry.status
                      )}`}
                    >
                      {entry.status}
                    </span>
                  </td>
                  <td className='px-4 py-2'>
                    <span
                      className={`inline-flex rounded px-2 py-0.5 text-xs font-medium ${
                        entry.kind === 'auto'
                          ? 'bg-violet-100 text-violet-800'
                          : 'bg-sky-100 text-sky-800'
                      }`}
                    >
                      {entry.kind}
                    </span>
                  </td>
                  <td className='max-w-xs truncate px-4 py-2 font-medium'>
                    {entry.companyName ?? '—'}
                  </td>
                  <td className='max-w-md truncate px-4 py-2 text-slate-700'>
                    {entry.message ?? '—'}
                  </td>
                  <td className='max-w-xs truncate px-4 py-2'>
                    <a
                      href={entry.scanSourceUrl}
                      target='_blank'
                      rel='noreferrer'
                      className='text-blue-600 hover:underline'
                      onClick={(event) => event.stopPropagation()}
                    >
                      {entry.scanSourceUrl}
                    </a>
                  </td>
                  <td className='whitespace-nowrap px-4 py-2 text-slate-500'>
                    {entry.completedAt
                      ? new Date(entry.completedAt).toLocaleString()
                      : entry.startedAt
                        ? new Date(entry.startedAt).toLocaleString()
                        : '—'}
                  </td>
                  <td className='whitespace-nowrap px-4 py-2 text-slate-500'>
                    {entry.durationMs != null ? `${entry.durationMs} ms` : '—'}
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}

export default AdminJobBoardPage;

'use client';

import { useCallback, useEffect, useState } from 'react';

import type {
  Company,
  JobBoardRefreshCompanyEmailsResponse,
  JobScanRecord,
  JobScanStep,
  PromoteCompanyResponse,
} from '@/shared/contracts/job-board';
import { Button } from '@/shared/ui/button';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from '@/shared/ui/dialog';

import { PromoteToOrganiserDialog } from './PromoteToOrganiserDialog';

const REFRESH_EMAILS_ENDPOINT = '/api/v2/jobs/companies';

const stepStatusColor = (status: string): string => {
  switch (status) {
    case 'completed':
      return 'bg-emerald-100 text-emerald-800';
    case 'running':
      return 'bg-blue-100 text-blue-800';
    case 'failed':
      return 'bg-rose-100 text-rose-800';
    case 'skipped':
      return 'bg-slate-100 text-slate-600';
    default:
      return 'bg-amber-100 text-amber-800';
  }
};

const renderStringList = (value: unknown, emptyText: string): React.JSX.Element => {
  const list = Array.isArray(value) ? value.filter((v): v is string => typeof v === 'string') : [];
  if (list.length === 0) {
    return <p className='text-sm text-slate-500'>{emptyText}</p>;
  }
  return (
    <ul className='list-disc space-y-1 pl-5 text-sm'>
      {list.map((item, idx) => (
        <li key={idx}>{item}</li>
      ))}
    </ul>
  );
};

const renderField = (label: string, value: unknown): React.JSX.Element | null => {
  if (value == null || value === '') return null;
  const display =
    typeof value === 'object' ? JSON.stringify(value) : String(value);
  return (
    <div className='flex flex-col gap-0.5'>
      <span className='text-xs uppercase tracking-wide text-slate-500'>{label}</span>
      <span className='text-sm'>{display}</span>
    </div>
  );
};

export type JobScanDetailDialogProps = {
  scan: JobScanRecord | null;
  company: Company | null;
  onClose: () => void;
  onPromoted?: (result: PromoteCompanyResponse) => void;
  onCompanyUpdated?: (company: Company) => void;
};

export function JobScanDetailDialog({
  scan,
  company: persistedCompany,
  onClose,
  onPromoted,
  onCompanyUpdated,
}: JobScanDetailDialogProps): React.JSX.Element {
  const [promoteOpen, setPromoteOpen] = useState(false);
  const [isRefreshingEmails, setIsRefreshingEmails] = useState(false);
  const [refreshEmailHeadless, setRefreshEmailHeadless] = useState(true);
  const [refreshEmailError, setRefreshEmailError] = useState<string | null>(null);
  const [refreshEmailSteps, setRefreshEmailSteps] = useState<JobScanStep[]>([]);
  const [companyState, setCompanyState] = useState<Company | null>(persistedCompany);
  const open = scan !== null;
  const listing = (scan?.evaluation?.listing as Record<string, unknown> | null) ?? null;
  const salary = (listing?.['salary'] as Record<string, unknown> | null) ?? null;

  const company = companyState;

  useEffect(() => {
    setCompanyState(persistedCompany);
  }, [persistedCompany]);

  const runEmailRefresh = useCallback(async (options: { useVision: boolean }): Promise<void> => {
    if (!companyState) return;
    setIsRefreshingEmails(true);
    setRefreshEmailError(null);
    setRefreshEmailSteps([]);

    try {
      const response = await fetch(
        `${REFRESH_EMAILS_ENDPOINT}/${encodeURIComponent(companyState.id)}/refresh-emails`,
        {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            useVision: options.useVision,
            autoPromote: false,
            headless: refreshEmailHeadless,
          }),
        }
      );
      const body = (await response.json()) as
        | JobBoardRefreshCompanyEmailsResponse
        | { error?: string };
      if (!response.ok) {
        throw new Error(
          (body as { error?: string }).error ??
            `Re-run email finder failed (HTTP ${response.status})`
        );
      }
      const { company: refreshed, steps } = body as JobBoardRefreshCompanyEmailsResponse;
      setCompanyState(refreshed);
      setRefreshEmailSteps(steps);
      onCompanyUpdated?.(refreshed);
    } catch (error) {
      setRefreshEmailError(error instanceof Error ? error.message : String(error));
    } finally {
      setIsRefreshingEmails(false);
    }
  }, [companyState, onCompanyUpdated, refreshEmailHeadless]);

  return (
    <Dialog
      open={open}
      onOpenChange={(next) => {
        if (!next) onClose();
      }}
    >
      <DialogContent className='max-h-[85vh] max-w-3xl overflow-y-auto'>
        <DialogHeader>
          <DialogTitle>
            {(listing?.['title'] as string | undefined) ?? 'Job scan'}
          </DialogTitle>
          <DialogDescription>
            {scan ? (
              <a
                href={scan.sourceUrl}
                target='_blank'
                rel='noreferrer'
                className='text-blue-600 hover:underline'
              >
                {scan.sourceUrl}
              </a>
            ) : null}
          </DialogDescription>
        </DialogHeader>

        {scan ? (
          <div className='space-y-6'>
            <section>
              <h3 className='mb-2 text-sm font-semibold text-slate-700'>Scan</h3>
              <div className='grid grid-cols-2 gap-3 sm:grid-cols-3'>
                {renderField('Status', scan.status)}
                {renderField('Provider', scan.provider)}
                {renderField('Confidence', scan.evaluation?.confidence)}
                {renderField('Model', scan.evaluation?.modelId)}
                {renderField('Company ID', scan.companyId)}
                {renderField('Listing ID', scan.jobListingId)}
                {renderField(
                  'Created',
                  scan.createdAt ? new Date(scan.createdAt).toLocaleString() : null
                )}
                {renderField(
                  'Completed',
                  scan.completedAt ? new Date(scan.completedAt).toLocaleString() : null
                )}
              </div>
              {scan.error ? (
                <div className='mt-3 rounded border border-rose-300 bg-rose-50 p-2 text-sm text-rose-800'>
                  {scan.error}
                </div>
              ) : null}
            </section>

            {company ? (
              <section>
                <h3 className='mb-2 text-sm font-semibold text-slate-700'>Company</h3>
                <div className='grid grid-cols-2 gap-3 sm:grid-cols-3'>
                  {renderField('Name', company['name'])}
                  {renderField('NIP', company['nip'])}
                  {renderField('Domain', company['domain'])}
                  {renderField('Industry', company['industry'])}
                  {renderField('Size', company['size'])}
                  {renderField('City', company['city'])}
                  {renderField('Postal code', company['postalCode'])}
                  {renderField('Country', company['country'])}
                </div>
                {company['addressLine'] ? (
                  <div className='mt-2'>{renderField('Address', company['addressLine'])}</div>
                ) : null}
                {company['description'] ? (
                  <p className='mt-2 whitespace-pre-wrap text-sm text-slate-700'>
                    {String(company['description'])}
                  </p>
                ) : null}
                <div className='mt-3'>
                  <div className='mb-1 flex items-center justify-between'>
                    <h4 className='text-xs font-semibold uppercase tracking-wide text-slate-500'>
                      Emails
                      {company.emailsSearchedAt
                        ? ` · searched ${new Date(company.emailsSearchedAt).toLocaleString()}`
                        : ''}
                    </h4>
                    <div className='flex flex-wrap items-center gap-2'>
                      <label className='flex items-center gap-2 rounded border border-slate-200 px-2 py-1 text-xs text-slate-600'>
                        <input
                          type='checkbox'
                          checked={refreshEmailHeadless}
                          onChange={(event) => setRefreshEmailHeadless(event.target.checked)}
                          disabled={isRefreshingEmails}
                        />
                        Headless browser
                      </label>
                      <Button
                        type='button'
                        size='sm'
                        variant='outline'
                        onClick={() => void runEmailRefresh({ useVision: false })}
                        disabled={isRefreshingEmails}
                      >
                        {isRefreshingEmails
                          ? 'Running scraper…'
                          : `Run browser scraper (${refreshEmailHeadless ? 'headless' : 'headed'})`}
                      </Button>
                      <Button
                        type='button'
                        size='sm'
                        variant='outline'
                        onClick={() => void runEmailRefresh({ useVision: true })}
                        disabled={isRefreshingEmails}
                      >
                        {isRefreshingEmails
                          ? 'Running scraper…'
                          : `Run vision finder (${refreshEmailHeadless ? 'headless' : 'headed'})`}
                      </Button>
                      <Button
                        type='button'
                        size='sm'
                        variant='outline'
                        onClick={() => setPromoteOpen(true)}
                      >
                        Promote to Organiser…
                      </Button>
                    </div>
                  </div>
                  {refreshEmailError ? (
                    <p className='mb-2 text-sm text-rose-800'>{refreshEmailError}</p>
                  ) : null}
                  {refreshEmailSteps.length > 0 ? (
                    <ul className='mb-2 space-y-2 text-xs text-slate-600'>
                      {refreshEmailSteps.map((step) => (
                        <li
                          key={`${step.key}-${step.startedAt}-${step.message ?? ''}`}
                          className='flex items-start gap-2 rounded border border-slate-200 p-2'
                        >
                          <span
                            className={`mt-0.5 inline-flex shrink-0 rounded px-2 py-0.5 text-[10px] font-medium ${stepStatusColor(
                              step.status
                            )}`}
                          >
                            {step.status}
                          </span>
                          <div className='min-w-0 flex-1'>
                            <div className='font-medium text-slate-700'>{step.label}</div>
                            <div>{step.message || 'No details'}</div>
                            <div className='mt-1 text-[10px] text-slate-500'>
                              {step.durationMs != null ? `${step.durationMs} ms` : ''}
                              {step.completedAt
                                ? ` · ${new Date(step.completedAt).toLocaleTimeString()}`
                                : ''}
                            </div>
                          </div>
                        </li>
                      ))}
                    </ul>
                  ) : null}
                  {company.emails.length === 0 ? (
                    <p className='text-sm text-slate-500'>
                      No emails found for this company yet.
                    </p>
                  ) : (
                    <ul className='space-y-1 text-sm'>
                      {company.emails.map((email) => (
                        <li key={email.address} className='flex items-baseline gap-2'>
                          <a
                            href={`mailto:${email.address}`}
                            className='text-blue-600 hover:underline'
                          >
                            {email.address}
                          </a>
                          {email.isPrimary ? (
                            <span className='inline-flex rounded bg-emerald-100 px-1.5 py-0.5 text-[10px] font-medium text-emerald-800'>
                              primary
                            </span>
                          ) : null}
                          {email.source ? (
                            <a
                              href={email.source}
                              target='_blank'
                              rel='noreferrer'
                              className='truncate text-xs text-slate-500 hover:underline'
                            >
                              {email.source}
                            </a>
                          ) : null}
                        </li>
                      ))}
                    </ul>
                  )}
                </div>
              </section>
            ) : null}

            {listing ? (
              <section>
                <h3 className='mb-2 text-sm font-semibold text-slate-700'>Listing</h3>
                <div className='grid grid-cols-2 gap-3 sm:grid-cols-3'>
                  {renderField('Contract', listing['contractType'])}
                  {renderField('Mode', listing['workMode'])}
                  {renderField('Level', listing['experienceLevel'])}
                  {renderField('City', listing['city'])}
                  {renderField('Region', listing['region'])}
                  {renderField('Country', listing['country'])}
                  {renderField('Posted', listing['postedAt'])}
                  {renderField('Expires', listing['expiresAt'])}
                </div>
                {salary ? (
                  <div className='mt-2 grid grid-cols-2 gap-3 sm:grid-cols-4'>
                    {renderField('Salary min', salary['min'])}
                    {renderField('Salary max', salary['max'])}
                    {renderField('Currency', salary['currency'])}
                    {renderField('Period', salary['period'])}
                    {renderField('Raw', salary['raw'])}
                  </div>
                ) : null}
                {listing['description'] ? (
                  <details className='mt-3 rounded border border-slate-200 p-2 text-sm'>
                    <summary className='cursor-pointer font-medium'>Description</summary>
                    <p className='mt-2 whitespace-pre-wrap text-slate-700'>
                      {String(listing['description'])}
                    </p>
                  </details>
                ) : null}
                <div className='mt-3 grid gap-4 sm:grid-cols-2'>
                  <div>
                    <h4 className='mb-1 text-xs font-semibold uppercase tracking-wide text-slate-500'>
                      Requirements
                    </h4>
                    {renderStringList(listing['requirements'], 'No requirements extracted.')}
                  </div>
                  <div>
                    <h4 className='mb-1 text-xs font-semibold uppercase tracking-wide text-slate-500'>
                      Responsibilities
                    </h4>
                    {renderStringList(
                      listing['responsibilities'],
                      'No responsibilities extracted.'
                    )}
                  </div>
                  <div>
                    <h4 className='mb-1 text-xs font-semibold uppercase tracking-wide text-slate-500'>
                      Benefits
                    </h4>
                    {renderStringList(listing['benefits'], 'No benefits extracted.')}
                  </div>
                  <div>
                    <h4 className='mb-1 text-xs font-semibold uppercase tracking-wide text-slate-500'>
                      Technologies
                    </h4>
                    {renderStringList(listing['technologies'], 'No technologies extracted.')}
                  </div>
                </div>
              </section>
            ) : null}

            {scan.steps.length > 0 ? (
              <section>
                <h3 className='mb-2 text-sm font-semibold text-slate-700'>Steps</h3>
                <ol className='space-y-2'>
                  {scan.steps.map((step) => (
                    <li
                      key={step.key}
                      className='flex items-start gap-3 rounded border border-slate-200 p-2 text-sm'
                    >
                      <span
                        className={`mt-0.5 inline-flex shrink-0 rounded px-2 py-0.5 text-xs font-medium ${stepStatusColor(
                          step.status
                        )}`}
                      >
                        {step.status}
                      </span>
                      <div className='flex-1'>
                        <div className='font-medium'>{step.label}</div>
                        {step.message ? (
                          <div className='text-slate-600'>{step.message}</div>
                        ) : null}
                        <div className='mt-1 text-xs text-slate-500'>
                          {step.durationMs != null ? `${step.durationMs} ms` : ''}
                          {step.completedAt
                            ? ` · ${new Date(step.completedAt).toLocaleTimeString()}`
                            : ''}
                        </div>
                      </div>
                    </li>
                  ))}
                </ol>
              </section>
            ) : null}

            <details className='rounded border border-slate-200 p-2 text-sm'>
              <summary className='cursor-pointer font-medium text-slate-600'>
                Raw evaluation JSON
              </summary>
              <pre className='mt-2 max-h-96 overflow-auto rounded bg-slate-50 p-2 text-xs'>
                {JSON.stringify(scan.evaluation, null, 2)}
              </pre>
            </details>
          </div>
        ) : null}
      </DialogContent>
      <PromoteToOrganiserDialog
        company={company}
        open={promoteOpen}
        onClose={() => setPromoteOpen(false)}
        {...(onPromoted ? { onPromoted } : {})}
      />
    </Dialog>
  );
}

'use client';

import { useCallback, useEffect, useState } from 'react';

import type {
  Company,
  FilemakerOrganisationHit,
  OrganisationSearchResponse,
  PromoteCompanyResponse,
} from '@/shared/contracts/job-board';
import { Button } from '@/shared/ui/button';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from '@/shared/ui/dialog';
import { Input } from '@/shared/ui/input';

const SEARCH_ENDPOINT = '/api/v2/jobs/organisations';

export type PromoteToOrganiserDialogProps = {
  company: Company | null;
  open: boolean;
  onClose: () => void;
  onPromoted?: (result: PromoteCompanyResponse) => void;
};

export function PromoteToOrganiserDialog({
  company,
  open,
  onClose,
  onPromoted,
}: PromoteToOrganiserDialogProps): React.JSX.Element {
  const [query, setQuery] = useState('');
  const [hits, setHits] = useState<FilemakerOrganisationHit[]>([]);
  const [selectedAddresses, setSelectedAddresses] = useState<Set<string>>(new Set());
  const [isSearching, setIsSearching] = useState(false);
  const [isPromoting, setIsPromoting] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [result, setResult] = useState<PromoteCompanyResponse | null>(null);

  // Seed query with the company name when the dialog opens; preselect all emails.
  useEffect(() => {
    if (!open) return;
    setQuery(company?.name ?? '');
    setSelectedAddresses(new Set((company?.emails ?? []).map((e) => e.address)));
    setHits([]);
    setError(null);
    setResult(null);
  }, [open, company]);

  const runSearch = useCallback(
    async (search: string): Promise<void> => {
      const trimmed = search.trim();
      if (trimmed.length < 2) {
        setHits([]);
        return;
      }
      setIsSearching(true);
      setError(null);
      try {
        const response = await fetch(
          `${SEARCH_ENDPOINT}?q=${encodeURIComponent(trimmed)}&limit=20`,
          { cache: 'no-store' }
        );
        if (!response.ok) throw new Error(`Search HTTP ${response.status}`);
        const body = (await response.json()) as OrganisationSearchResponse;
        setHits(body.hits);
      } catch (err) {
        setError(err instanceof Error ? err.message : String(err));
      } finally {
        setIsSearching(false);
      }
    },
    []
  );

  // Debounced auto-search.
  useEffect(() => {
    if (!open) return;
    const handle = window.setTimeout(() => {
      void runSearch(query);
    }, 300);
    return () => window.clearTimeout(handle);
  }, [open, query, runSearch]);

  const handlePromote = useCallback(
    async (organizationId: string): Promise<void> => {
      if (!company) return;
      setIsPromoting(true);
      setError(null);
      try {
        const response = await fetch(
          `/api/v2/jobs/companies/${encodeURIComponent(company.id)}/promote`,
          {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
              organizationId,
              addresses: [...selectedAddresses],
            }),
          }
        );
        const body = (await response.json()) as PromoteCompanyResponse | { error?: string };
        if (!response.ok) {
          throw new Error(
            (body as { error?: string }).error ?? `Promote HTTP ${response.status}`
          );
        }
        setResult(body as PromoteCompanyResponse);
        onPromoted?.(body as PromoteCompanyResponse);
      } catch (err) {
        setError(err instanceof Error ? err.message : String(err));
      } finally {
        setIsPromoting(false);
      }
    },
    [company, selectedAddresses, onPromoted]
  );

  const toggleAddress = (address: string): void => {
    setSelectedAddresses((prev) => {
      const next = new Set(prev);
      if (next.has(address)) next.delete(address);
      else next.add(address);
      return next;
    });
  };

  return (
    <Dialog open={open} onOpenChange={(next) => !next && onClose()}>
      <DialogContent className='max-h-[85vh] max-w-2xl overflow-y-auto'>
        <DialogHeader>
          <DialogTitle>Promote to Filemaker organisation</DialogTitle>
          <DialogDescription>
            Search for the matching CRM organisation and write the scraped emails into{' '}
            <code className='rounded bg-slate-100 px-1'>filemaker_emails</code> with a link to the
            organisation. Existing emails are reused; existing links are left untouched.
          </DialogDescription>
        </DialogHeader>

        {!company ? (
          <p className='text-sm text-slate-500'>No company selected.</p>
        ) : (
          <div className='space-y-4'>
            <section>
              <h3 className='mb-1 text-sm font-semibold text-slate-700'>
                Emails to promote ({selectedAddresses.size} selected)
              </h3>
              {company.emails.length === 0 ? (
                <p className='text-sm text-slate-500'>No emails were scraped for this company.</p>
              ) : (
                <ul className='space-y-1 text-sm'>
                  {company.emails.map((email) => (
                    <li key={email.address} className='flex items-center gap-2'>
                      <input
                        type='checkbox'
                        checked={selectedAddresses.has(email.address)}
                        onChange={() => toggleAddress(email.address)}
                      />
                      <span>{email.address}</span>
                      {email.isPrimary ? (
                        <span className='inline-flex rounded bg-emerald-100 px-1.5 py-0.5 text-[10px] font-medium text-emerald-800'>
                          primary
                        </span>
                      ) : null}
                    </li>
                  ))}
                </ul>
              )}
            </section>

            <section>
              <h3 className='mb-1 text-sm font-semibold text-slate-700'>Find organisation</h3>
              <Input
                placeholder='Name, NIP, or KRS'
                value={query}
                onChange={(event) => setQuery(event.target.value)}
              />
              <div className='mt-2 max-h-72 overflow-y-auto rounded border border-slate-200'>
                {isSearching ? (
                  <p className='p-3 text-sm text-slate-500'>Searching…</p>
                ) : hits.length === 0 ? (
                  <p className='p-3 text-sm text-slate-500'>
                    {query.trim().length < 2 ? 'Type at least 2 characters.' : 'No matches.'}
                  </p>
                ) : (
                  <ul className='divide-y divide-slate-100'>
                    {hits.map((hit) => (
                      <li
                        key={hit.id}
                        className='flex items-start justify-between gap-3 p-3 text-sm hover:bg-slate-50'
                      >
                        <div className='min-w-0 flex-1'>
                          <div className='font-medium'>{hit.name}</div>
                          <div className='text-xs text-slate-500'>
                            {hit.taxId ? `NIP ${hit.taxId} · ` : ''}
                            {hit.krs ? `KRS ${hit.krs} · ` : ''}
                            {hit.city ?? ''}
                          </div>
                          {hit.tradingName ? (
                            <div className='text-xs text-slate-500'>{hit.tradingName}</div>
                          ) : null}
                        </div>
                        <Button
                          type='button'
                          size='sm'
                          disabled={isPromoting || selectedAddresses.size === 0}
                          onClick={() => void handlePromote(hit.id)}
                        >
                          {isPromoting ? 'Saving…' : 'Promote'}
                        </Button>
                      </li>
                    ))}
                  </ul>
                )}
              </div>
            </section>

            {error ? (
              <div className='rounded border border-rose-300 bg-rose-50 p-2 text-sm text-rose-800'>
                {error}
              </div>
            ) : null}

            {result ? (
              <div className='rounded border border-emerald-300 bg-emerald-50 p-3 text-sm'>
                <div className='font-medium text-emerald-900'>
                  Promoted to {result.organizationName}
                </div>
                <ul className='mt-1 list-disc space-y-0.5 pl-5 text-emerald-800'>
                  {result.promoted.map((p) => (
                    <li key={p.linkId}>
                      {p.address} — {p.status.replace('-', ' ')}
                    </li>
                  ))}
                  {result.skipped.map((s, idx) => (
                    <li key={`skipped-${idx}`} className='text-amber-800'>
                      {s.address}: {s.reason}
                    </li>
                  ))}
                </ul>
              </div>
            ) : null}
          </div>
        )}
      </DialogContent>
    </Dialog>
  );
}

import 'server-only';

import { randomUUID } from 'crypto';

import {
  COMPANIES_COLLECTION,
  normalizeCompany,
  type Company,
  type CompanyInput,
} from '@/shared/contracts/job-board';
import { getMongoDb } from '@/shared/lib/db/mongo-client';
import { ErrorSystem } from '@/shared/utils/observability/error-system';

type CompanyDoc = Omit<Company, 'createdAt' | 'updatedAt'> & {
  createdAt: Date;
  updatedAt: Date;
};

let indexesEnsured: Promise<void> | null = null;
let inMemory: Company[] = [];

const useMemory = (): boolean => !process.env['MONGODB_URI'];

const ensureIndexes = async (): Promise<void> => {
  if (useMemory()) return;
  if (indexesEnsured) return indexesEnsured;
  indexesEnsured = (async () => {
    try {
      const db = await getMongoDb();
      const collection = db.collection<CompanyDoc>(COMPANIES_COLLECTION);
      await Promise.all([
        collection.createIndex({ id: 1 }, { unique: true }),
        collection.createIndex(
          { nip: 1 },
          { unique: true, partialFilterExpression: { nip: { $type: 'string' } } }
        ),
        collection.createIndex(
          { domain: 1 },
          { partialFilterExpression: { domain: { $type: 'string' } } }
        ),
        collection.createIndex({ name: 1 }),
      ]);
    } catch (error) {
      void ErrorSystem.captureException(error, {
        service: 'companies.repository',
        action: 'ensureIndexes',
      });
    }
  })();
  return indexesEnsured;
};

const toRecord = (doc: CompanyDoc): Company =>
  normalizeCompany({
    ...doc,
    createdAt: doc.createdAt.toISOString(),
    updatedAt: doc.updatedAt.toISOString(),
  });

const normalizeName = (name: string): string => name.trim().toLowerCase().replace(/\s+/g, ' ');

const matchKey = (company: Company): { nip: string | null; domain: string | null; name: string } => ({
  nip: company.nip?.trim() || null,
  domain: company.domain?.trim().toLowerCase() || null,
  name: normalizeName(company.name),
});

export async function findCompanyMatch(input: {
  nip?: string | null;
  domain?: string | null;
  name?: string | null;
}): Promise<Company | null> {
  const nip = input.nip?.trim() || null;
  const domain = input.domain?.trim().toLowerCase() || null;
  const name = input.name ? normalizeName(input.name) : null;

  if (useMemory()) {
    if (nip) {
      const byNip = inMemory.find((c) => c.nip === nip);
      if (byNip) return byNip;
    }
    if (domain) {
      const byDomain = inMemory.find((c) => c.domain?.toLowerCase() === domain);
      if (byDomain) return byDomain;
    }
    if (name) {
      const byName = inMemory.find((c) => normalizeName(c.name) === name);
      if (byName) return byName;
    }
    return null;
  }

  await ensureIndexes();
  const db = await getMongoDb();
  const collection = db.collection<CompanyDoc>(COMPANIES_COLLECTION);

  if (nip) {
    const doc = await collection.findOne({ nip });
    if (doc) return toRecord(doc);
  }
  if (domain) {
    const doc = await collection.findOne({ domain });
    if (doc) return toRecord(doc);
  }
  if (name) {
    const docs = await collection.find({}).toArray();
    const match = docs.find((doc) => normalizeName(doc.name) === name);
    if (match) return toRecord(match);
  }
  return null;
}

export async function listCompanies(input: { limit?: number | null } = {}): Promise<Company[]> {
  const limit = input.limit != null ? Math.max(1, Math.trunc(input.limit)) : 100;

  if (useMemory()) {
    return [...inMemory]
      .sort((a, b) => {
        const aTs = a.createdAt ? Date.parse(a.createdAt) : 0;
        const bTs = b.createdAt ? Date.parse(b.createdAt) : 0;
        return bTs - aTs;
      })
      .slice(0, limit);
  }

  await ensureIndexes();
  const db = await getMongoDb();
  const docs = await db
    .collection<CompanyDoc>(COMPANIES_COLLECTION)
    .find({})
    .sort({ createdAt: -1 })
    .limit(limit)
    .toArray();
  return docs.map(toRecord);
}

export async function getCompanyById(id: string): Promise<Company | null> {
  const trimmedId = id.trim();
  if (!trimmedId) return null;

  if (useMemory()) {
    return inMemory.find((c) => c.id === trimmedId) ?? null;
  }

  await ensureIndexes();
  const db = await getMongoDb();
  const collection = db.collection<CompanyDoc>(COMPANIES_COLLECTION);
  const doc = await collection.findOne({ id: trimmedId });
  return doc ? toRecord(doc) : null;
}

export async function upsertCompany(input: CompanyInput): Promise<Company> {
  const normalized = normalizeCompany({ ...input, id: input.id || randomUUID() });
  const now = new Date();

  if (useMemory()) {
    const existingIndex = inMemory.findIndex((c) => c.id === normalized.id);
    const next: Company = {
      ...normalized,
      createdAt: normalized.createdAt ?? now.toISOString(),
      updatedAt: now.toISOString(),
    };
    if (existingIndex >= 0) {
      inMemory[existingIndex] = next;
    } else {
      inMemory = [next, ...inMemory];
    }
    return next;
  }

  await ensureIndexes();
  const db = await getMongoDb();
  const collection = db.collection<CompanyDoc>(COMPANIES_COLLECTION);
  const { createdAt: _c, updatedAt: _u, ...rest } = normalized;
  const result = await collection.findOneAndUpdate(
    { id: normalized.id },
    {
      $set: { ...rest, updatedAt: now },
      $setOnInsert: { createdAt: normalized.createdAt ? new Date(normalized.createdAt) : now },
    },
    { upsert: true, returnDocument: 'after' }
  );
  return result
    ? toRecord(result)
    : { ...normalized, createdAt: now.toISOString(), updatedAt: now.toISOString() };
}

/**
 * Upsert by match keys: NIP first, then domain, then normalized name.
 * Returns the resulting (possibly merged) company. Existing fields take precedence over null
 * incoming values; non-null incoming values override.
 */
export async function upsertCompanyByMatch(input: CompanyInput): Promise<Company> {
  const candidate = normalizeCompany({ ...input, id: input.id || randomUUID() });
  const keys = matchKey(candidate);
  const existing = await findCompanyMatch({
    nip: keys.nip,
    domain: keys.domain,
    name: keys.name,
  });

  if (!existing) {
    return await upsertCompany(candidate);
  }

  const merged: CompanyInput = { ...existing };
  for (const [key, value] of Object.entries(candidate)) {
    if (value !== null && value !== undefined && value !== '') {
      (merged as Record<string, unknown>)[key] = value;
    }
  }
  merged.id = existing.id;
  return await upsertCompany(merged);
}

