const runDeterministic = async (input: EmailFinderInput): Promise<UnifiedEmailFinderResult> => {
  const r = await findCompanyEmailsDeterministic({
    website: input.website ?? null,
    domain: input.domain ?? null,
    companyName: input.companyName ?? null,
    headless: input.headless ?? null,
  });
  return {
    durationMs: r.durationMs,
    emails: r.emails,
    ...(r.error !== undefined ? { error: r.error } : {}),
    iterationsRun: 0,
    reasoning: null,
    steps: r.steps,
    strategy: 'deterministic',
    visitedUrls: r.visitedUrls,
  };
};

export const findCompanyEmails = async (
  input: EmailFinderInput
): Promise<UnifiedEmailFinderResult> => {
  const strategy = resolveStrategy(input.strategy);
  return strategy === 'vision' ? await runVision(input) : await runDeterministic(input);
};

import 'server-only';

import { runPlaywrightEngineTask } from '@/features/playwright/server/runtime';
import { ErrorSystem } from '@/shared/utils/observability/error-system';

export type GoogleSearchHit = {
  title: string;
  url: string;
  snippet: string;
};

export type GoogleSearchResult = {
  hits: GoogleSearchHit[];
  query: string;
  error?: string;
};

const SEARCH_SCRIPT = `
  export default async ({ page, input }) => {
    const url = 'https://www.google.com/search?q=' + encodeURIComponent(input.query) + '&hl=pl';
    await page.goto(url, { waitUntil: 'domcontentloaded', timeout: 30000 });
    try { await page.waitForLoadState('networkidle', { timeout: 10000 }); } catch {}

    // Dismiss the consent dialog if present (varies by region).
    try {
      const consentButton = await page.$('button[aria-label*="Accept" i], button[aria-label*="Zgadzam" i], #L2AGLb');
      if (consentButton) {
        await consentButton.click({ timeout: 3000 });
        await page.waitForTimeout(800);
      }
    } catch {}

    const hits = await page.evaluate(() => {
      const results = [];
      const blocks = document.querySelectorAll('div.g, div.MjjYud');
      for (const block of blocks) {
        const link = block.querySelector('a[href^="http"]');
        const title = block.querySelector('h3');
        const snippet = block.querySelector('div[data-snc], div[data-sncf], span.VwiC3b');
        if (!link || !title) continue;
        const href = link.href || '';
        if (!href || href.startsWith('https://www.google.')) continue;
        results.push({
          url: href,
          title: title.textContent || '',
          snippet: snippet ? snippet.textContent || '' : '',
        });
        if (results.length >= 8) break;
      }
      return results;
    });

    return { hits };
  };
`;

const useSearch = (): boolean => {
  if (process.env['JOB_BOARD_USE_GOOGLE_SEARCH']?.toLowerCase() === 'true') return true;
  return false;
};

export const searchGoogle = async (query: string): Promise<GoogleSearchResult> => {
  if (!useSearch()) {
    return {
      hits: [],
      query,
      error: 'Google search disabled (set JOB_BOARD_USE_GOOGLE_SEARCH=true to enable).',
    };
  }

  try {
    const run = await runPlaywrightEngineTask({
      request: {
        script: SEARCH_SCRIPT,
        startUrl: 'https://www.google.com/',
        input: { query },
        timeoutMs: 45_000,
        browserEngine: 'chromium',
      },
      instance: {
        kind: 'custom',
        family: 'scrape',
        label: 'Job board company website search',
        tags: ['job-board', 'google-search'],
      },
    });

    if (run.status === 'failed' || run.status === 'cancelled' || run.status === 'canceled') {
      return { hits: [], query, error: run.error ?? `Search run status=${run.status}` };
    }

    const result = (run.result ?? {}) as { returnValue?: { hits?: GoogleSearchHit[] } };
    const hits = (result.returnValue?.hits ?? []).filter(
      (hit): hit is GoogleSearchHit =>
        typeof hit?.url === 'string' && typeof hit?.title === 'string'
    );
    return { hits, query };
  } catch (error) {
    void ErrorSystem.captureException(error, {
      service: 'job-scans.google-search',
      action: 'searchGoogle',
      query,
    });
    return {
      hits: [],
      query,
      error: error instanceof Error ? error.message : String(error),
    };
  }
};

const SOCIAL_DOMAINS = [
  'linkedin.com',
  'facebook.com',
  'instagram.com',
  'twitter.com',
  'x.com',
  'youtube.com',
  'pracuj.pl',
  'justjoin.it',
  'nofluffjobs.com',
  'goldenline.pl',
  'olx.pl',
];

const isCorporateUrl = (url: string): boolean => {
  try {
    const host = new URL(url).hostname.toLowerCase().replace(/^www\./, '');
    return !SOCIAL_DOMAINS.some((d) => host === d || host.endsWith(`.${d}`));
  } catch {
    return false;
  }
};

export const findCompanyWebsite = async (input: {
  companyName: string;
  city?: string | null;
}): Promise<{ website: string | null; domain: string | null; error?: string }> => {
  const baseQuery = `${input.companyName}${input.city ? ` ${input.city}` : ''} oficjalna strona`;
  const result = await searchGoogle(baseQuery);
  if (result.error && result.hits.length === 0) {
    return { website: null, domain: null, error: result.error };
  }
  const corporate = result.hits.find((hit) => isCorporateUrl(hit.url));
  if (!corporate) return { website: null, domain: null };
  try {
    const url = new URL(corporate.url);
    return {
      website: `${url.protocol}//${url.hostname}`,
      domain: url.hostname.toLowerCase().replace(/^www\./, ''),
    };
  } catch {
    return { website: null, domain: null };
  }
};

import 'server-only';

import { randomUUID } from 'crypto';

import {
  JOB_LISTINGS_COLLECTION,
  normalizeJobListing,
  type JobListing,
  type JobListingInput,
} from '@/shared/contracts/job-board';
import { getMongoDb } from '@/shared/lib/db/mongo-client';
import { ErrorSystem } from '@/shared/utils/observability/error-system';

type JobListingDoc = Omit<JobListing, 'createdAt' | 'updatedAt' | 'postedAt' | 'expiresAt'> & {
  createdAt: Date;
  updatedAt: Date;
  postedAt: Date | null;
  expiresAt: Date | null;
};

let indexesEnsured: Promise<void> | null = null;
let inMemory: JobListing[] = [];

const useMemory = (): boolean => !process.env['MONGODB_URI'];

const ensureIndexes = async (): Promise<void> => {
  if (useMemory()) return;
  if (indexesEnsured) return indexesEnsured;
  indexesEnsured = (async () => {
    try {
      const db = await getMongoDb();
      const collection = db.collection<JobListingDoc>(JOB_LISTINGS_COLLECTION);
      await Promise.all([
        collection.createIndex({ id: 1 }, { unique: true }),
        collection.createIndex({ companyId: 1, createdAt: -1 }),
        collection.createIndex(
          { sourceUrl: 1 },
          { unique: true, partialFilterExpression: { sourceUrl: { $type: 'string' } } }
        ),
      ]);
    } catch (error) {
      void ErrorSystem.captureException(error, {
        service: 'job-listings.repository',
        action: 'ensureIndexes',
      });
    }
  })();
  return indexesEnsured;
};

const toRecord = (doc: JobListingDoc): JobListing =>
  normalizeJobListing({
    ...doc,
    createdAt: doc.createdAt.toISOString(),
    updatedAt: doc.updatedAt.toISOString(),
    postedAt: doc.postedAt ? doc.postedAt.toISOString() : null,
    expiresAt: doc.expiresAt ? doc.expiresAt.toISOString() : null,
  });

export async function findJobListingBySourceUrl(sourceUrl: string): Promise<JobListing | null> {
  const url = sourceUrl.trim();
  if (!url) return null;

  if (useMemory()) {
    return inMemory.find((j) => j.sourceUrl === url) ?? null;
  }

  await ensureIndexes();
  const db = await getMongoDb();
  const doc = await db.collection<JobListingDoc>(JOB_LISTINGS_COLLECTION).findOne({ sourceUrl: url });
  return doc ? toRecord(doc) : null;
}

export async function listJobListings(input: {
  companyId?: string | null;
  limit?: number | null;
} = {}): Promise<JobListing[]> {
  const limit = input.limit != null ? Math.max(1, Math.trunc(input.limit)) : 100;
  const companyId = input.companyId?.trim() || null;

  if (useMemory()) {
    const filtered = companyId ? inMemory.filter((j) => j.companyId === companyId) : inMemory;
    return [...filtered]
      .sort((a, b) => {
        const aTs = a.createdAt ? Date.parse(a.createdAt) : 0;
        const bTs = b.createdAt ? Date.parse(b.createdAt) : 0;
        return bTs - aTs;
      })
      .slice(0, limit);
  }

  await ensureIndexes();
  const db = await getMongoDb();
  const filter = companyId ? { companyId } : {};
  const docs = await db
    .collection<JobListingDoc>(JOB_LISTINGS_COLLECTION)
    .find(filter)
    .sort({ createdAt: -1 })
    .limit(limit)
    .toArray();
  return docs.map(toRecord);
}

export async function listJobListingsByCompany(companyId: string): Promise<JobListing[]> {
  const id = companyId.trim();
  if (!id) return [];

  if (useMemory()) {
    return inMemory.filter((j) => j.companyId === id);
  }

  await ensureIndexes();
  const db = await getMongoDb();
  const docs = await db
    .collection<JobListingDoc>(JOB_LISTINGS_COLLECTION)
    .find({ companyId: id })
    .sort({ createdAt: -1 })
    .toArray();
  return docs.map(toRecord);
}

export async function upsertJobListing(input: JobListingInput): Promise<JobListing> {
  const normalized = normalizeJobListing({ ...input, id: input.id || randomUUID() });
  const now = new Date();

  if (useMemory()) {
    const existingIndex = inMemory.findIndex(
      (j) => j.id === normalized.id || j.sourceUrl === normalized.sourceUrl
    );
    const next: JobListing = {
      ...normalized,
      createdAt: normalized.createdAt ?? now.toISOString(),
      updatedAt: now.toISOString(),
    };
    if (existingIndex >= 0) {
      inMemory[existingIndex] = { ...next, id: inMemory[existingIndex]!.id };
    } else {
      inMemory = [next, ...inMemory];
    }
    return inMemory[existingIndex >= 0 ? existingIndex : 0]!;
  }

  await ensureIndexes();
  const db = await getMongoDb();
  const collection = db.collection<JobListingDoc>(JOB_LISTINGS_COLLECTION);
  const { createdAt: _c, updatedAt: _u, postedAt, expiresAt, ...rest } = normalized;
  const result = await collection.findOneAndUpdate(
    { sourceUrl: normalized.sourceUrl },
    {
      $set: {
        ...rest,
        postedAt: postedAt ? new Date(postedAt) : null,
        expiresAt: expiresAt ? new Date(expiresAt) : null,
        updatedAt: now,
      },
      $setOnInsert: {
        createdAt: normalized.createdAt ? new Date(normalized.createdAt) : now,
      },
    },
    { upsert: true, returnDocument: 'after' }
  );
  return result
    ? toRecord(result)
    : {
        ...normalized,
        createdAt: now.toISOString(),
        updatedAt: now.toISOString(),
      };
}

import 'server-only';

import { randomUUID } from 'crypto';

import {
  JOB_SCANS_COLLECTION,
  normalizeJobScanRecord,
  type JobScanRecord,
  type JobScanRecordInput,
  type JobScanStatus,
} from '@/shared/contracts/job-board';
import { getMongoDb } from '@/shared/lib/db/mongo-client';
import { ErrorSystem } from '@/shared/utils/observability/error-system';

type JobScanDoc = Omit<JobScanRecord, 'createdAt' | 'updatedAt' | 'completedAt'> & {
  createdAt: Date;
  updatedAt: Date;
  completedAt: Date | null;
};

let indexesEnsured: Promise<void> | null = null;
let inMemory: JobScanRecord[] = [];

const useMemory = (): boolean => !process.env['MONGODB_URI'];

const ensureIndexes = async (): Promise<void> => {
  if (useMemory()) return;
  if (indexesEnsured) return indexesEnsured;
  indexesEnsured = (async () => {
    try {
      const db = await getMongoDb();
      const collection = db.collection<JobScanDoc>(JOB_SCANS_COLLECTION);
      await Promise.all([
        collection.createIndex({ id: 1 }, { unique: true }),
        collection.createIndex({ status: 1, updatedAt: -1 }),
        collection.createIndex({ sourceUrl: 1, createdAt: -1 }),
        collection.createIndex(
          { engineRunId: 1 },
          { unique: true, partialFilterExpression: { engineRunId: { $type: 'string' } } }
        ),
      ]);
    } catch (error) {
      void ErrorSystem.captureException(error, {
        service: 'job-scans.repository',
        action: 'ensureIndexes',
      });
    }
  })();
  return indexesEnsured;
};

const toRecord = (doc: JobScanDoc): JobScanRecord =>
  normalizeJobScanRecord({
    ...doc,
    createdAt: doc.createdAt.toISOString(),
    updatedAt: doc.updatedAt.toISOString(),
    completedAt: doc.completedAt ? doc.completedAt.toISOString() : null,
  });

const sortByCreatedAtDesc = (scans: JobScanRecord[]): JobScanRecord[] =>
  [...scans].sort((a, b) => {
    const aTs = a.createdAt ? Date.parse(a.createdAt) : 0;
    const bTs = b.createdAt ? Date.parse(b.createdAt) : 0;
    return bTs - aTs;
  });

export async function listJobScans(input: {
  statuses?: JobScanStatus[] | null;
  companyId?: string | null;
  limit?: number | null;
} = {}): Promise<JobScanRecord[]> {
  const limit = input.limit != null ? Math.max(1, Math.trunc(input.limit)) : 50;
  const statuses = input.statuses ?? null;
  const companyId = input.companyId?.trim() || null;

  if (useMemory()) {
    let filtered = inMemory;
    if (statuses) filtered = filtered.filter((s) => statuses.includes(s.status));
    if (companyId) filtered = filtered.filter((s) => s.companyId === companyId);
    return sortByCreatedAtDesc(filtered).slice(0, limit);
  }

  await ensureIndexes();
  const db = await getMongoDb();
  const filter: Record<string, unknown> = {};
  if (statuses) filter['status'] = { $in: statuses };
  if (companyId) filter['companyId'] = companyId;
  const docs = await db
    .collection<JobScanDoc>(JOB_SCANS_COLLECTION)
    .find(filter)
    .sort({ createdAt: -1 })
    .limit(limit)
    .toArray();
  return docs.map(toRecord);
}

export async function getJobScanById(id: string): Promise<JobScanRecord | null> {
  const trimmedId = id.trim();
  if (!trimmedId) return null;

  if (useMemory()) {
    return inMemory.find((s) => s.id === trimmedId) ?? null;
  }

  await ensureIndexes();
  const db = await getMongoDb();
  const doc = await db.collection<JobScanDoc>(JOB_SCANS_COLLECTION).findOne({ id: trimmedId });
  return doc ? toRecord(doc) : null;
}

export async function upsertJobScan(input: JobScanRecordInput): Promise<JobScanRecord> {
  const normalized = normalizeJobScanRecord({ ...input, id: input.id || randomUUID() });
  const now = new Date();

  if (useMemory()) {
    const next: JobScanRecord = {
      ...normalized,
      createdAt: normalized.createdAt ?? now.toISOString(),
      updatedAt: now.toISOString(),
      completedAt: normalized.completedAt ?? null,
    };
    const existingIndex = inMemory.findIndex((s) => s.id === normalized.id);
    if (existingIndex >= 0) {
      inMemory[existingIndex] = next;
    } else {
      inMemory = [next, ...inMemory];
    }
    return next;
  }

  await ensureIndexes();
  const db = await getMongoDb();
  const collection = db.collection<JobScanDoc>(JOB_SCANS_COLLECTION);
  const { createdAt: _c, updatedAt: _u, completedAt, ...rest } = normalized;
  const result = await collection.findOneAndUpdate(
    { id: normalized.id },
    {
      $set: {
        ...rest,
        completedAt: completedAt ? new Date(completedAt) : null,
        updatedAt: now,
      },
      $setOnInsert: { createdAt: normalized.createdAt ? new Date(normalized.createdAt) : now },
    },
    { upsert: true, returnDocument: 'after' }
  );
  return result
    ? toRecord(result)
    : {
        ...normalized,
        createdAt: now.toISOString(),
        updatedAt: now.toISOString(),
      };
}

export async function updateJobScan(
  id: string,
  updates: Partial<JobScanRecordInput>
): Promise<JobScanRecord | null> {
  const existing = await getJobScanById(id);
  if (!existing) return null;
  return await upsertJobScan({ ...existing, ...updates, id: existing.id });
}

